What does this program print?

```cpp
#include <iostream>

template <typename T>
T halve(T x)
{
    return x / 2;
}

template <>
double halve<double>(double x)
{
    return x / 2.0;
}

int main()
{
    std::cout << halve(10) << '\n';
    std::cout << halve(7) << '\n';
    std::cout << halve(7.0) << '\n';
    return 0;
}
```

